#include <stdio.h>
#include <string.h>
int main() {
    char S[51];
    int T, Li, Pi, i, j, count, res;
    scanf("%s", S);
    scanf("%d", &T);
    for (i = 0; i < T; i++) {
        scanf("%d %d", &Li, &Pi);
        res = 0;
        for (j = 0; j <= strlen(S) - Li; j++) {
            count = 0;
            char sub[Li + 1];
            strncpy(sub, S + j, Li);
            sub[Li] = '\0';
            for (int k = 0; k <= strlen(S) - Li; k++) {
                char sub2[Li + 1];
                strncpy(sub2, S + k, Li);
                sub2[Li] = '\0';
                if (strcmp(sub, sub2) == 0) count++;
            }
            if (count == Pi) res++;
        }
        printf("%d\n", res);
    }
    return 0;
}

