code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String S = sc.next();
        int T = sc.nextInt();
        for (int i = 0; i < T; i++) {
            int Li = sc.nextInt();
            int Pi = sc.nextInt();
            int res = 0;
            for (int j = 0; j <= S.length() - Li; j++) {
                int count = 0;
                String sub = S.substring(j, j + Li);
                for (int k = 0; k <= S.length() - Li; k++) {
                    String sub2 = S.substring(k, k + Li);
                    if (sub.equals(sub2)) count++;
                }
                if (count == Pi) res++;
            }
            System.out.println(res);
        }
    }
}

